    int even_sum = 0, odd_sum = 0, l_even = 0, l_odd = 0, count = 0;
    for (int i = 0; i < nums.length; ++i) {
        if (i % 2 == 0) even_sum += nums[i];
        else odd_sum += nums[i];
    }
    for (int i = 0; i < nums.length; ++i) {
        if (i % 2 == 0) {
            even_sum -= nums[i];
            if (l_even + odd_sum == l_odd + even_sum) ++count;
            l_even += nums[i];
        } else {
            odd_sum -= nums[i];
            if (l_even + odd_sum == l_odd + even_sum) ++count;
            l_odd += nums[i];
        }
    }
    return count;
}
